var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이거나….. 먹어라!","JPN":"これでも……食らえ！","ENG":"Take that!","TWN":"你……接招吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"크윽!!","JPN":"くっ！！","ENG":"Hngh!","TWN":"唔唔！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"허억…… 허억……","JPN":"はあ……はあ……","ENG":"*Huff... Huff...*","TWN":"呼呼……呼呼……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아직 멀었어, 아가씨! 이제 겨우 몸이 풀렸거든!","JPN":"まだまだだぜ、お嬢ちゃん！　今までのは肩慣らしだ！","ENG":"Girl, I’m not done yet! I was just warming up!","TWN":"還差得遠呢！這才只是暖身而已！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 괜찮아요?!","JPN":"ミナさん！　大丈夫ですか？","ENG":"You okay, Mina?","TWN":"米娜，你沒事吧？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아슬아슬했지만…… 다치진 않았어.","JPN":"ギリギリだったけど……怪我はしてないよ。","ENG":"That was close, but I’m not hurt.","TWN":"剛才是有點驚險……但我沒受傷。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그보다 등대에서 광선이 더 빠르게 방출되고 있어!","JPN":"そんなことより、灯台からの光線放出速度が速くなってる！","ENG":"The Lighthouse is emitting the light faster than before!","TWN":"重點不是那個啦，重點是燈塔射出光束的頻率比之前更快！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이래선 접근이 불가능해!","JPN":"これじゃあ近づくのは無理だ！","ENG":"We can’t get any closer!","TWN":"這樣我們根本無法接近！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 건 그쪽 특기로 기억하는데, 소년.","JPN":"こういうのはそっちが得意とすることだったと思うんだが、少年？","ENG":"I thought you were specialized in dealing with things like this, boy.","TWN":"年輕人，我記得這不是你最擅長的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저 공격 어떻게 튕겨내거나 할 수는 없나?","JPN":"あの攻撃をうまいこと弾いたりできないか？","ENG":"Can’t you deflect the light?","TWN":"有辦法把那個攻擊反射回去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"……무리입니다.","JPN":"……無理です。","ENG":"... I can’t.","TWN":"……沒辦法。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어떤 원리인지는 모르겠지만…… 저 광선, 미나 양의 클리포트 인자와 흡사한 성질을 가지고 있어요.","JPN":"どのような原理なのかわかりませんが……\\nあの光線は、ミナさんのクリフォト・ファクターに酷似した性質を持っています。","ENG":"I don’t know how, but it seems the light is very similar to Mina’s Qliphoth Factor.","TWN":"雖然我不清楚是什麼原理……但那個光束有著和米娜的逆卡巴類似的性質。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아무리 저라고 해도 함부로 받아내려고 했다간 무사하지 못할 겁니다.","JPN":"いくら僕でも、むやみに受け止めようとすれば無事では済まないでしょう。","ENG":"I don’t think I’ll survive if I try to deflect it.","TWN":"就算是我，也很難保證會沒事。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대령이 벌어준 시간도 한계가 있어. 빨리 등대를 파괴하지 않으면……","JPN":"大佐が稼いでくれた時間にも限界がある。早く灯台を壊さないと……","ENG":"The Colonel won’t last long. If we don’t destroy the Lighthouse quickly...","TWN":"上校能爭取的時間是有限的，再不趕快把燈塔破壞掉……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……제가 앞장설게요.","JPN":"……私がやってみます。","ENG":"... I’ll go first.","TWN":"……我來打頭陣吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L28_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"제이나……?","JPN":"ジェイナ……？","ENG":"Jaina?","TWN":"婕娜……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"제 힘은 리플레이서 퀸과 동일한 초재생 능력이에요.","JPN":"私の力はリプレイサー・クイーンと同じく、超再生能力です。","ENG":"I have the super regenerative power, the same as the Replacer Queen.","TWN":"我和克隆·女皇一樣有超再生能力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"기억에 따르면……. 죽음 직전까지 가더라도 살아날 수 있답니다.","JPN":"記憶によれば……死の直前までいっても再生することができます。","ENG":"According to my memory, I can even come back from near-death experiences.","TWN":"我的記憶沒錯的話……只要在死亡前抵達就可以活下來。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그 말은, 설마…….","JPN":"ということは、まさか……","ENG":"You mean...","TWN":"你的意思該不會是……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"공격을 튕겨낼 수는 없지만, 몸으로 받아내서 틈을 만들 수는 있을 거예요.","JPN":"攻撃を弾くことはできませんが、\\n体で受け止めて隙を作ることはできると思います。","ENG":"I can’t deflect the light, but I’ll be able to block it to make a path for you.","TWN":"雖然我無法將攻擊反射回去，但我可以用我的身體來爭取時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"죽지만 않으면 살아날 수 있으니까……","JPN":"死にさえしなければ再生するので……","ENG":"I will come back if I don’t die...","TWN":"只要我不死就能活下去……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"멍청한 소리 하지 마!","JPN":"バカなことを言うな！","ENG":"Don't be stupid!","TWN":"你在說什麼蠢話！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저 공격이 장난 같아 보여? 그러다 정말 죽기라도 하면 어쩌려고?","JPN":"あの攻撃が軽く見えるか？\\nそんなことをして本当に死んじまったらどうすんだ！","ENG":"Do you think that’s a joke? What if it actually kills you?","TWN":"你以為這是兒戲嗎？萬一你真的死掉的話怎麼辦？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……죄송해요.","JPN":"……ごめんなさい。","ENG":"... I'm sorry.","TWN":"……對不起。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐? 갑자기 왜 사과를……?","JPN":"なっ！？　なんで急に謝罪を……？","ENG":"Huh? Why do you apologize?","TWN":"做什麼？幹嘛突然道歉……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 퀸이…… 당신의 형을 살해했다고 들었어요.","JPN":"リプレイサー・クイーンが……あなたのお兄さんを殺したと聞きました。","ENG":"I heard... that the Replacer Queen killed your brother.","TWN":"我聽說……克隆·女皇是殺你哥哥的兇手。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……지금 그 이야기를 왜 하는 거지?","JPN":"……今ここでその話をする理由はなんだ？","ENG":"... Why do you mention it now?","TWN":"……幹嘛突然提起這件事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"말했을 텐데. 형을 위한 내 복수는 이미 완결됐어.","JPN":"言ったはずだ。兄のための復讐はもう終わった。","ENG":"I told you, I already avenged my brother.","TWN":"我應該有說過吧，我已經替哥哥報仇了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그렇게 말해 주셔서 고마워요.","JPN":"そう言ってくださってありがとうございます。","ENG":"Thank you for saying that.","TWN":"謝謝你這麼說。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하지만 그 일에 대해 제가 직접 당신에게 사과한 적은 없잖아요.","JPN":"ですが、そのことについて私が直接あなたに謝ったことはないのです。","ENG":"But I never actually apologized to you for that.","TWN":"但我從來沒有為這件事親口向你道歉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"저는 제가 리플레이서 퀸과 다른 사람이라고 생각하지만, 그 여자 때문에 고통 받았던 누군가에게는 그렇지 않을지도 몰라요.","JPN":"私は自分がリプレイサー・クイーンとは違う人間だと思っています。\\nですが、あの女のせいで苦しんだ誰かにとっては、そうではないかもしれません。","ENG":"I believe that I’m a different person from the Replacer Queen, but those who suffered because of her might disagree.","TWN":"雖然我認為我和克隆·女皇是不同人，但被她傷害過的人或許不這麼想。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그러니까, 증명하고 싶어요. 저는 자기 잘못에 대한 책임을 지지 않고 사라진 그 여자와 다르다는 걸요.","JPN":"だから、証明したいんです。\\n私は、自分の過ちに対して責任すら取らずに消えたあの女とは違うということを。","ENG":"So I want to prove myself. That I’m different from that woman, who tortured others and went away without paying for her sins.","TWN":"所以我想證明，我和那個犯錯後不負責任消失的女人不一樣！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그리고 지금이 바로 그 때인 것 같아요.","JPN":"そして、今がまさにその時だと思います。","ENG":"And I think this is the time.","TWN":"而現在就是我證明的時候！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그러니까…… 너무 늦지만 말아 주세요.","JPN":"だから……どうか間に合ってくださいね。","ENG":"So... don’t be late.","TWN":"所以……請不要攔我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 멈춰! 제이나 크로펠!!","JPN":"おい、やめろ！　ジェイナ・クロペル！！","ENG":"Hey, stop! Jaina Kropel!","TWN":"喂，你站住！婕娜·克洛佩爾！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああっ！！","ENG":"Argh!","TWN":"啊啊啊！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 무슨 일이야?!","JPN":"なに？　どうなっているの！？","ENG":"What? What’s going on?","TWN":"怎麼了？發生什麼事？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 아직…… 버틸 수 있어……","JPN":"ま……まだ……耐えられる………","ENG":"I-I can... I can take it...","TWN":"我……我還撐得住……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"크윽……! 하아……! 아직, 한 번이라면……!","JPN":"くぅ…！　ぐはっ……！ 　まだ、あと1回なら……！","ENG":"*Pant* I can... take one more...","TWN":"唔……！呼呼……！還可以再撐一次……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭘 멍하니 바라보고 있나?!","JPN":"何をボケっとしてるんだ！？","ENG":"Stop standing there like an idiot!","TWN":"你們傻在那幹嘛？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"달려! 당장 저 빌어먹을 등대를 부숴버려!","JPN":"走れ！　今すぐあのクソみたいな灯台を壊すぞ！","ENG":"Move! Go and destroy the Lighthouse!","TWN":"衝啊！快去毀掉那該死的燈塔！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아, 알았어! 선배!","JPN":"わ、わかった！　先輩！","ENG":"O-okay! Shiyoon!","TWN":"喔，好，前輩！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가고 있습니다! 지금이에요!!","JPN":"向かっています！　今です！！","ENG":"I’m coming! NOW!","TWN":"前進中！就是現在！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_BOSS_04_HOLY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}}]`);export{e as default};